<template>
	<div ref="rootRef" :class="`scramble-text ${className}`" :style="style">
		<p>
			<slot />
		</p>
	</div>
</template>

<script setup>
import { gsap } from "gsap";
import { ScrambleTextPlugin } from "gsap/ScrambleTextPlugin";
import { SplitText } from "gsap/SplitText";
import { onMounted, onUnmounted, ref, watch } from "vue";
const props = defineProps({
  radius: { type: Number, required: false, default: 100 },
  duration: { type: Number, required: false, default: 1.2 },
  speed: { type: Number, required: false, default: 0.5 },
  scrambleChars: { type: String, required: false, default: ".:" },
  className: { type: String, required: false, default: "" },
  style: { type: Object, required: false, default: () => ({}) }
});
gsap.registerPlugin(SplitText, ScrambleTextPlugin);
const rootRef = ref(null);
let splitText = null;
let handleMove = null;
const initializeScrambleText = () => {
  if (!rootRef.value) return;
  const pElement = rootRef.value.querySelector("p");
  if (!pElement) return;
  splitText = new SplitText(pElement, {
    type: "chars",
    charsClass: "inline-block will-change-transform"
  });
  splitText.chars.forEach((el) => {
    const c = el;
    gsap.set(c, { attr: { "data-content": c.innerHTML } });
  });
  handleMove = (e) => {
    if (!splitText) return;
    splitText.chars.forEach((el) => {
      const c = el;
      const { left, top, width, height } = c.getBoundingClientRect();
      const dx = e.clientX - (left + width / 2);
      const dy = e.clientY - (top + height / 2);
      const dist = Math.hypot(dx, dy);
      if (dist < props.radius) {
        gsap.to(c, {
          overwrite: true,
          duration: props.duration * (1 - dist / props.radius),
          scrambleText: {
            text: c.dataset.content || "",
            chars: props.scrambleChars,
            speed: props.speed
          },
          ease: "none"
        });
      }
    });
  };
  rootRef.value.addEventListener("pointermove", handleMove);
};
const cleanup = () => {
  if (rootRef.value && handleMove) {
    rootRef.value.removeEventListener("pointermove", handleMove);
  }
  if (splitText) {
    splitText.revert();
    splitText = null;
  }
  handleMove = null;
};
onMounted(() => {
  initializeScrambleText();
});
onUnmounted(() => {
  cleanup();
});
watch([() => props.radius, () => props.duration, () => props.speed, () => props.scrambleChars], () => {
  cleanup();
  initializeScrambleText();
});
</script>
